const { attachMissionDetailMeta } = require('./index-mission-nav.js')

const CALENDAR_CACHE_MAX_AGE_MS = 5 * 60 * 1000
const CALENDAR_PAGE_LIMIT = 80

function normalizeMissionType(type) {
  return type === 'completed' ? 'completed' : 'upcoming'
}

function normalizeMissionItem(mission, options) {
  const {
    type,
    index = 0,
    baseIndex = 0,
    formatDate
  } = options || {}

  const normalizedType = normalizeMissionType(type)
  const isCompleted = normalizedType === 'completed'

  return attachMissionDetailMeta({
    ...mission,
    _wxkey: `${isCompleted ? 'm-1' : 'm-0'}-${baseIndex + index}-${(mission.id != null ? mission.id : '')}`,
    formattedTime: mission.launchTime ? formatDate(mission.launchTime, 'MM月DD日 HH:mm') : '时间未知'
  }, {
    id: mission.id,
    detailType: normalizedType
  })
}

async function fetchMissionListData(options) {
  const {
    type,
    limit = 50,
    offset = 0,
    getUpcomingMissions,
    getCompletedMissions,
    formatDate,
    filterExpiredMissions
  } = options || {}

  const normalizedType = normalizeMissionType(type)
  const fetcher = normalizedType === 'completed' ? getCompletedMissions : getUpcomingMissions
  const res = await fetcher(limit, offset)
  const baseIndex = offset || 0
  const list = (res.list || []).map((mission, index) => normalizeMissionItem(mission, {
    type: normalizedType,
    index,
    baseIndex,
    formatDate
  }))

  return {
    res,
    list: normalizedType === 'completed' ? list : filterExpiredMissions(list)
  }
}

function buildMissionListSetData(type, missions, res = {}, filterExpiredMissions) {
  const normalizedType = normalizeMissionType(type)
  const list = Array.isArray(missions) ? missions : []

  if (normalizedType === 'completed') {
    return {
      completedMissions: list,
      completedMissionsOffset: getMissionNextOffset(res, 0),
      completedMissionsHasMore: !!res.hasMore
    }
  }

  return {
    upcomingMissions: filterExpiredMissions(list),
    missionsOffset: getMissionNextOffset(res, 0),
    missionsHasMore: !!res.hasMore
  }
}

function getMissionNextOffset(res = {}, fallbackOffset = 0) {
  const nextOffset = Number(res && res.nextOffset)
  if (Number.isFinite(nextOffset) && nextOffset >= 0) {
    return nextOffset
  }

  const safeFallback = Math.max(0, Number(fallbackOffset) || 0)
  const listLength = Array.isArray(res && res.list) ? res.list.length : 0
  return safeFallback + listLength
}

function mergeMissionPages(type, currentList, incomingList, filterExpiredMissions) {
  const normalizedType = normalizeMissionType(type)
  const merged = []
    .concat(Array.isArray(currentList) ? currentList : [])
    .concat(Array.isArray(incomingList) ? incomingList : [])

  if (normalizedType === 'completed') {
    return merged.sort((a, b) => {
      const timeA = a && a.launchTime ? new Date(a.launchTime).getTime() : 0
      const timeB = b && b.launchTime ? new Date(b.launchTime).getTime() : 0
      return timeB - timeA
    })
  }

  return filterExpiredMissions(merged.sort((a, b) => {
    const timeA = a && a.launchTime ? new Date(a.launchTime).getTime() : 0
    const timeB = b && b.launchTime ? new Date(b.launchTime).getTime() : 0
    return timeA - timeB
  }))
}

function getValidCalendarCache(cache, maxAgeMs = CALENDAR_CACHE_MAX_AGE_MS) {
  const cached = cache && typeof cache === 'object' ? cache : null
  const cachedAll = cached && Array.isArray(cached.all) ? cached.all : []
  const cachedAt = cached && Number(cached.ts)
  const hasUsableCache = !!(
    cached &&
    cached.byDate &&
    cachedAt &&
    cachedAll.length > 0 &&
    Date.now() - cachedAt < maxAgeMs
  )

  if (!hasUsableCache) {
    return null
  }

  return {
    allMissions: cachedAll,
    upOffset: Math.max(0, Number(cached.upOffset) || 0),
    compOffset: Math.max(0, Number(cached.compOffset) || 0),
    upHasMore: cached.upHasMore !== false,
    compHasMore: cached.compHasMore !== false
  }
}

function buildCalendarMissionBatch(options) {
  const {
    upcomingResult,
    completedResult,
    processMission,
    currentMissions = []
  } = options || {}

  const upList = ((upcomingResult && upcomingResult.list) || []).map((mission, index) => processMission(mission, index, true))
  const compList = ((completedResult && completedResult.list) || []).map((mission, index) => processMission(mission, index, false))
  const appendedMissions = [...upList, ...compList]

  return {
    allMissions: [...(Array.isArray(currentMissions) ? currentMissions : []), ...appendedMissions],
    appendedMissions,
    nextState: {
      upOffset: getMissionNextOffset(upcomingResult && upcomingResult.res, upcomingResult && upcomingResult.offset),
      compOffset: getMissionNextOffset(completedResult && completedResult.res, completedResult && completedResult.offset),
      upHasMore: !!(upcomingResult && upcomingResult.res && upcomingResult.res.hasMore),
      compHasMore: !!(completedResult && completedResult.res && completedResult.res.hasMore)
    }
  }
}

module.exports = {
  CALENDAR_CACHE_MAX_AGE_MS,
  CALENDAR_PAGE_LIMIT,
  fetchMissionListData,
  buildMissionListSetData,
  getMissionNextOffset,
  mergeMissionPages,
  getValidCalendarCache,
  buildCalendarMissionBatch
}
