function filterExpiredMissions(missions) {
  const now = Date.now()
  return (missions || []).filter((mission) => {
    if (!mission.launchTime) return true
    const launchTs = new Date(mission.launchTime).getTime()
    if (launchTs > now) return true
    const category = mission.statusCategory || ''
    if (category === 'success' || category === 'failure' || category === 'partial') return false
    return true
  })
}

function getStatusTextZh(status) {
  const text = String(status || '').trim()
  if (!text) return '计划中'
  const lower = text.toLowerCase()
  if (lower.includes('success') || lower.includes('succeeded')) return '成功'
  if (lower.includes('failure') || lower.includes('failed')) return '失败'
  if (lower.includes('partial')) return '部分成功'
  if (lower.includes('delayed') || lower.includes('hold')) return '延迟'
  if (lower.includes('go') || lower.includes('ready') || lower.includes('green')) return '就绪'
  if (lower.includes('tbd') || lower.includes('to be determined')) return '待定'
  if (lower.includes('tbc') || lower.includes('to be confirmed')) return '待确认'
  if (lower.includes('scheduled') || lower.includes('schedule') || lower.includes('pending')) return '计划中'
  if (text.includes('成功')) return '成功'
  if (text.includes('失败')) return '失败'
  if (text.includes('部分成功')) return '部分成功'
  if (text.includes('延迟')) return '延迟'
  if (text.includes('就绪') || text.includes('准备')) return '就绪'
  if (text.includes('待定')) return '待定'
  if (text.includes('待确认')) return '待确认'
  if (text.includes('计划')) return '计划中'
  return text
}

function formatSecondsText(value) {
  return String(value == null ? 0 : value).padStart(2, '0')
}

function getPreviousSecondText(value) {
  const second = Number(value) || 0
  return formatSecondsText((second + 1) % 60)
}

function getNextSecondText(value) {
  const second = Number(value) || 0
  return formatSecondsText((second + 59) % 60)
}

function getSecondsReel(value) {
  const current = formatSecondsText(value)
  return [getPreviousSecondText(value), current, getNextSecondText(value)]
}

